export interface NfseOption { value: string; label: string; }

// ── Tipo auxiliar para serviços com metadados de incidência ─────────────────
export interface ServicoNacionalItem extends NfseOption {
    codigo: string;
    descricao: string;
    /** true = incidência no Local da Prestação (LP) — art. 3º LC 116/03 */
    lp?: boolean;
    /** true = incidência no Estabelecimento/Domicílio do Prestador (EP) */
    ep?: boolean;
    /** true = incidência no Estabelecimento/Domicílio do Tomador (ET) */
    et?: boolean;
    /** true = exige grupo <obra> na DPS */
    obra?: boolean;
}

