// ── Helpers para lookup por código ──────────────────────────────────────────
export function getServicoNacionalByCodigo(codigo: string): ServicoNacionalItem | undefined {
    const c = codigo.replace(/\D/g, '').padStart(6, '0');
    return SERVICO_NACIONAL_OPTIONS.find(s => s.codigo === c);
}

export function getRegraIncidenciaByServico(codigo: string): { lp: boolean; ep: boolean; et: boolean; obra: boolean } {
    const s = getServicoNacionalByCodigo(codigo);
    return { lp: !!s?.lp, ep: !!s?.ep, et: !!s?.et, obra: !!s?.obra };
}

export function getIndopByCodigo(codigo: string): NfseOption | undefined {
    const c = codigo.replace(/\D/g, '').padStart(6, '0');
    return INDOP_OPTIONS.find(i => i.value === c);
}

