// ── Lookup helpers ────────────────────────────────────────────────────────────
export function getMunicipioByCodigo(value: string): MunicipioItem | undefined {
    const clean = value.trim();
    return MUNICIPIO_OPTIONS.find(
        m => m.codigo === clean || m.value === clean ||
             m.municipio.toLowerCase() === clean.toLowerCase(),
    );
}

export function getNbsByCodigo(raw: string): NbsItem | undefined {
    const digits = raw.replace(/\D/g, '');
    if (!digits) return undefined;
    return NBS_OPTIONS.find(
        n => n.codigo.replace(/\D/g, '') === digits || n.value === raw || n.codigo === raw,
    );
}

export function onlyCodigo(value: string): string {
    if (!value) return '';
    return value.trim().split(/\s/)[0];
}

